/// <reference types="node" />
import { EventEmitter } from 'events';
/**
 * Convert a `.rule` file to a `.fst` file.
 * ```
 * import {Rulify} from 'jibo-dev';
 * const fstPath = Rulify.sync('/path/to/file.rule');
 * console.log("FST file saved to: ", fstPath);
 * ```
 * @class Rulify
 */
export default class Rulify {
    private static _nlu;
    /**
     * Synchronous version of rulify.
     * @method Rulify.sync
     * @param {String} src Either the contents of the rule or the path to the source (.rule or .fst)
     * @param {String} output Name of file to write, will default to src with `.fst` extension.
     * @return {String} The output file saved.
     */
    static sync(src: any, output: any): any;
    /**
     * Asynchronous version of rulify.
     * @method Rulify.async
     * @param {String} src Either the contents of the rule or the path to the source (.rule or .fst)
     * @param {String} [output] Name of file to write, will default to src with `.fst` extension.
     * @param {Rulify~Callback} callback Called when the conversion completes.
     */
    static async(src: any, output: any, callback: any): void;
    /**
     * Get the reference the NLU parser.
     * @method Rulify.nlu
     * @return {NLU} The nlu parser.
     */
    static readonly nlu: any;
    /**
     * Get the reference the NLU parser.
     * @method Rulify.exec
     * @param {Array<String>} files List of files to load
     * @param {String} input Input directory
     * @param {String} output Output directory
     * @param {Boolean} [verbose=false] Extra logging
     * @return {EventEmitter} Emitter dispatches 'end', 'fileError', 'compileError', and 'log'
     */
    static exec(input: string, output: string, verbose?: boolean): EventEmitter;
    /**
     * Compiles a skill's launch rules into a single .fst file. The launch rules are listed in
     * the "rulesToBuild" array of the skill's package.json. The name of the .fst file to output
     * to is found in "launchRule" (it should default to something if launchRule is not found or
     * is an array -- to do)
     *
     * @method Rulify.compileLaunchRules
     * @param {String} packagePath input directory, containing package.json
     * @param {Boolean} [verbose=false] Extra logging
     * @param {Boolean} [forceCompile=false] Force compile even if cache exists
     * @return {EventEmitter} Emitter dispatches 'end', 'fileError', 'compileError', and 'log'
     */
    static compileLaunchRules(packagePath: string, verbose?: boolean, forceCompile?: boolean): EventEmitter;
    /**
     * Given a set of .rule files, compile each of them in memory into a .fst file.
     * When this is done, the method will return an array of URIs which contain either
     * the paths to the .fst files on disk or handles to their instances in memory.
     *
     * @param  {string[]}     files        Array of paths to rule files, which are relative
     * @param  {string[]}     outUris      Array that will receive set of outputted URIs
     * @param  {string}       inputFolder  Base input folder
     * @param  {string}       outputFolder Base output folder (relevant only when outputting
     *                                     .fst files to disk)
     * @param  {boolean}      outputToDisk If true, .fst files will be outputted to disk;
     *                                     otherwise they exist in memory, referred to by
     *                                     their handles.
     * @return {RulifyErrors}              error structure, if any errors. Otherwise, return
     *                                     null
     */
    private static processRulesFiles(files, outUris, inputFolder, outputFolder, outputToDisk);
    /**
     * Give a set of uris to compiled .fst files (either the paths of the files on
     * disk or handles to their in-memory instances), compile a master .fst file.
     * @param  {string[]} uris Array of uris
     */
    private static compileUnion(uris);
}
